/* VetClinic Custom Styles */

/* Dashboard cards */
.stat-card {
    border-left: 4px solid #0d6efd;
    transition: transform 0.2s;
}
.stat-card:hover {
    transform: translateY(-2px);
}
.stat-card.border-success { border-left-color: #198754; }
.stat-card.border-warning { border-left-color: #ffc107; }
.stat-card.border-info { border-left-color: #0dcaf0; }
.stat-card.border-danger { border-left-color: #dc3545; }

/* Calendar grid */
.calendar-container {
    overflow-x: auto;
}
.calendar-grid {
    display: grid;
    grid-template-columns: 80px repeat(7, 1fr);
    min-width: 800px;
    border: 1px solid #dee2e6;
    border-radius: 0.375rem;
}
.calendar-header {
    background-color: #f8f9fa;
    padding: 0.5rem;
    text-align: center;
    font-weight: 600;
    border-bottom: 2px solid #dee2e6;
    border-right: 1px solid #dee2e6;
}
.calendar-header.today {
    background-color: #cfe2ff;
}
.time-label {
    background-color: #f8f9fa;
    padding: 0.25rem 0.5rem;
    font-size: 0.8rem;
    color: #6c757d;
    border-right: 1px solid #dee2e6;
    border-bottom: 1px solid #f0f0f0;
    display: flex;
    align-items: flex-start;
    justify-content: flex-end;
    min-height: 60px;
}
.calendar-cell {
    border-right: 1px solid #dee2e6;
    border-bottom: 1px solid #f0f0f0;
    min-height: 60px;
    padding: 2px;
    position: relative;
    cursor: pointer;
}
.calendar-cell:hover {
    background-color: #f0f8ff;
}
.calendar-cell.today {
    background-color: #f8fbff;
}

/* Appointment blocks */
.appointment-block {
    padding: 0.25rem 0.5rem;
    border-radius: 0.25rem;
    font-size: 0.75rem;
    margin-bottom: 2px;
    cursor: pointer;
    color: white;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
