                        </div>
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Diagnosis *</label>
                            <InputText class="form-control" @bind-Value="model.Diagnosis" />
                            <ValidationMessage For="() => model.Diagnosis" />
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-6 mb-3">
                            <label class="form-label">Treatment *</label>
                            <InputTextArea class="form-control" @bind-Value="model.Treatment" rows="3" />
