                                <p class="mb-1"><strong>Diagnosis:</strong> @record.Diagnosis</p>
                                <p class="mb-1"><strong>Treatment:</strong> @record.Treatment</p>
                                @if (!string.IsNullOrWhiteSpace(record.Notes))
                                {
                                    <p class="mb-0 text-muted"><strong>Notes:</strong> @record.Notes</p>
                                }
                            </div>
                            <div>
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => EditRecord(record)">Edit</button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        }
    }
</div>

@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private List<MedicalRecord> records = new();
    private bool showForm = false;
    private MedicalRecord? editingRecord;
    private RecordFormModel model = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var context = DbContextFactory.CreateDbContext();
        pet = await context.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == PetId);
        records = await context.MedicalRecords
            .Where(r => r.PetId == PetId)
            .OrderByDescending(r => r.Date)
            .ToListAsync();
    }

    private void ToggleRecordForm()
    {
        showForm = !showForm;
        if (showForm)
        {
            editingRecord = null;
            model = new RecordFormModel { Date = DateTime.Today };
        }
    }

    private void EditRecord(MedicalRecord record)
    {
        editingRecord = record;
        model = new RecordFormModel
        {
            Id = record.Id,
            Date = record.Date,
            Veterinarian = record.Veterinarian,
            Diagnosis = record.Diagnosis,
            Treatment = record.Treatment,
            Notes = record.Notes
        };
        showForm = true;
    }

    private async Task HandleSubmit()
    {
        using var context = DbContextFactory.CreateDbContext();

        if (model.Id > 0)
        {
            var record = await context.MedicalRecords.FindAsync(model.Id);
            if (record != null)
            {
                record.Date = model.Date;
                record.Veterinarian = model.Veterinarian!;
                record.Diagnosis = model.Diagnosis!;
                record.Treatment = model.Treatment!;
                record.Notes = model.Notes ?? string.Empty;
                await context.SaveChangesAsync();
            }
        }
        else
        {
            var record = new MedicalRecord
            {
                PetId = PetId,
                Date = model.Date,
                Veterinarian = model.Veterinarian!,
                Diagnosis = model.Diagnosis!,
                Treatment = model.Treatment!,
                Notes = model.Notes ?? string.Empty
            };
            context.MedicalRecords.Add(record);
            await context.SaveChangesAsync();
        }

        showForm = false;
        editingRecord = null;
        await LoadData();
    }

    private class RecordFormModel
    {
        public int Id { get; set; }

        [Required]
        public DateTime Date { get; set; } = DateTime.Today;

        [Required(ErrorMessage = "Veterinarian is required")]
        public string? Veterinarian { get; set; }

        [Required(ErrorMessage = "Diagnosis is required")]
        public string? Diagnosis { get; set; }

        [Required(ErrorMessage = "Treatment is required")]
        public string? Treatment { get; set; }

        public string? Notes { get; set; }
    }
}

