@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Models

@inject IDbContextFactory<ApplicationDbContext> DbContextFactory
@inject NavigationManager Navigation

<PageTitle>Patients</PageTitle>

<div class="container-fluid">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>Patients</h2>
        <button class="btn btn-primary" @onclick="ToggleNewPatientForm">
            @(showForm ? "Cancel" : "➕ Register New Pet")
        </button>
    </div>

    @if (showForm)
    {
        <VetClinic.Components.Pages.Patients.PatientForm
            Pet="editingPet"
            Owners="owners"
            OnSave="HandleSave"
            OnCancel="ToggleNewPatientForm" />
    }

    <!-- Search -->
    <div class="mb-3">
        <div class="search-box">
            <span class="search-icon">🔍</span>
            <input type="text" class="form-control" placeholder="Search by pet name or owner name..."
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
    </div>

    <!-- Patient Table -->
    <div class="table-responsive">
        <table class="table table-hover">
            <thead class="table-light">
                <tr>
                    <th>Pet Name</th>
                    <th>Species</th>
                    <th>Breed</th>
                    <th>Age</th>
                    <th>Weight</th>
                    <th>Owner</th>
                    <th>Phone</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var pet in FilteredPets)
                {
                    <tr>
                        <td><strong>@pet.Name</strong></td>
                        <td>@pet.Species</td>
                        <td>@pet.Breed</td>
                        <td>@GetAge(pet.DateOfBirth)</td>
                        <td>@pet.Weight kg</td>
                        <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                        <td>@pet.Owner.Phone</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => EditPet(pet)">Edit</button>
                            <button class="btn btn-sm btn-outline-info" @onclick='() => Navigation.NavigateTo($"/patients/{pet.Id}/history")'>History</button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    @if (!FilteredPets.Any())
    {
        <div class="text-center text-muted py-4">
            <p>No patients found.</p>
        </div>
    }
</div>

@code {
    private List<Pet> pets = new();
    private List<Owner> owners = new();
    private string searchTerm = string.Empty;
    private bool showForm = false;
    private Pet? editingPet;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p =>
            p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Owner.FirstName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Owner.LastName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        await LoadData();

        var uri = Navigation.ToAbsoluteUri(Navigation.Uri);
        if (Microsoft.AspNetCore.WebUtilities.QueryHelpers.ParseQuery(uri.Query).ContainsKey("new"))
        {
            showForm = true;
            editingPet = null;
        }
    }

    private async Task LoadData()
    {
        using var context = DbContextFactory.CreateDbContext();
        pets = await context.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await context.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ToggleNewPatientForm()
    {
        showForm = !showForm;
        editingPet = showForm ? null : editingPet;
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showForm = true;
    }

    private async Task HandleSave()
    {
        showForm = false;
        editingPet = null;
        await LoadData();
    }

    private string GetAge(DateTime dob)
    {
        var age = DateTime.Today.Year - dob.Year;
        if (dob > DateTime.Today.AddYears(-age)) age--;
        return age <= 0 ? "< 1 yr" : $"{age} yr";
    }
}

