@code {
    [Parameter] public Pet? Pet { get; set; }
    [Parameter] public List<Owner>? Owners { get; set; }
    [Parameter] public EventCallback OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private PatientFormModel model = new();
    private string? errorMessage;

    protected override void OnParametersSet()
    {
        if (Pet != null && Pet.Id > 0)
        {
            model = new PatientFormModel
            {
                PetId = Pet.Id,
                PetName = Pet.Name,
                Species = Pet.Species,
                Breed = Pet.Breed,
                DateOfBirth = Pet.DateOfBirth,
                Weight = Pet.Weight,
                OwnerId = Pet.OwnerId
            };
        }
        else
        {
            model = new PatientFormModel { DateOfBirth = DateTime.Today.AddYears(-1) };
        }
    }

    private void OnOwnerSelected() { }

    private async Task HandleSubmit()
    {
        errorMessage = null;
        try
        {
            using var context = DbContextFactory.CreateDbContext();

            int ownerId = model.OwnerId;
            if (ownerId == 0)
            {
                if (string.IsNullOrWhiteSpace(model.OwnerFirstName) || string.IsNullOrWhiteSpace(model.OwnerLastName))
                {
                    errorMessage = "Owner first and last name are required when creating a new owner.";
                    return;
                }
                var newOwner = new Owner
                {
                    FirstName = model.OwnerFirstName!,
                    LastName = model.OwnerLastName!,
                    Phone = model.OwnerPhone ?? string.Empty,
                    Email = model.OwnerEmail ?? string.Empty
                };
                context.Owners.Add(newOwner);
                await context.SaveChangesAsync();
                ownerId = newOwner.Id;
            }

            if (model.PetId > 0)
            {
                var pet = await context.Pets.FindAsync(model.PetId);
                if (pet != null)
                {
                    pet.Name = model.PetName!;
                    pet.Species = model.Species!;
                    pet.Breed = model.Breed ?? string.Empty;
                    pet.DateOfBirth = model.DateOfBirth;
                    pet.Weight = model.Weight;
                    pet.OwnerId = ownerId;
                    await context.SaveChangesAsync();
                }
            }
            else
            {
                var pet = new Pet
                {
                    Name = model.PetName!,
                    Species = model.Species!,
                    Breed = model.Breed ?? string.Empty,
                    DateOfBirth = model.DateOfBirth,
                    Weight = model.Weight,
                    OwnerId = ownerId
                };
                context.Pets.Add(pet);
                await context.SaveChangesAsync();
            }

            await OnSave.InvokeAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Error saving patient: {ex.Message}";
        }
    }

    private async Task HandleCancel() => await OnCancel.InvokeAsync();

    private class PatientFormModel
    {
        public int PetId { get; set; }

        [Required(ErrorMessage = "Pet name is required")]
        public string? PetName { get; set; }

        [Required(ErrorMessage = "Species is required")]
        public string? Species { get; set; }

        public string? Breed { get; set; }

        [Required]
        public DateTime DateOfBirth { get; set; } = DateTime.Today.AddYears(-1);

        [Range(0, 1000)]
        public decimal Weight { get; set; }

        public int OwnerId { get; set; }

        public string? OwnerFirstName { get; set; }
        public string? OwnerLastName { get; set; }
        public string? OwnerPhone { get; set; }
        public string? OwnerEmail { get; set; }
    }
}

@page "/patients/{PetId:int}/history"

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Models
@using System.ComponentModel.DataAnnotations

@inject IDbContextFactory<ApplicationDbContext> DbContextFactory
@inject NavigationManager Navigation

<PageTitle>Medical History</PageTitle>

<div class="container-fluid">
    @if (pet == null)
    {
        <p>Loading...</p>
    }
    else
    {
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <button class="btn btn-outline-secondary btn-sm mb-2" @onclick='() => Navigation.NavigateTo("/patients")'>← Back to Patients</button>
                <h2>@pet.Name - Medical History</h2>
                <p class="text-muted">
                    @pet.Species @(!string.IsNullOrEmpty(pet.Breed) ? $"({pet.Breed})" : "") |
                    Owner: @pet.Owner.FirstName @pet.Owner.LastName |
                    Weight: @pet.Weight kg |
                    DOB: @pet.DateOfBirth.ToString("MMM d, yyyy")
                </p>
            </div>
            <button class="btn btn-primary" @onclick="ToggleRecordForm">
                @(showForm ? "Cancel" : "➕ Add Record")
            </button>
        </div>

        @if (showForm)
        {
            <div class="form-section">
                <h5>@(editingRecord != null ? "Edit Medical Record" : "New Medical Record")</h5>
                <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="medicalRecordForm">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />

                    <div class="row">
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Date *</label>
                            <InputDate class="form-control" @bind-Value="model.Date" />
                        </div>
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Veterinarian *</label>
                            <InputText class="form-control" @bind-Value="model.Veterinarian" />
                            <ValidationMessage For="() => model.Veterinarian" />
                        </div>
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Diagnosis *</label>
                            <InputText class="form-control" @bind-Value="model.Diagnosis" />
                            <ValidationMessage For="() => model.Diagnosis" />
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-6 mb-3">
                            <label class="form-label">Treatment *</label>
                            <InputTextArea class="form-control" @bind-Value="model.Treatment" rows="3" />
                            <ValidationMessage For="() => model.Treatment" />
                        </div>
                        <div class="col-md-6 mb-3">
                            <label class="form-label">Notes</label>
                            <InputTextArea class="form-control" @bind-Value="model.Notes" rows="3" />
                        </div>
                    </div>
                    <button type="submit" class="btn btn-primary">Save Record</button>
                </EditForm>
            </div>
        }

        @if (records.Count == 0)
        {
            <div class="text-center text-muted py-4">
                <p>No medical records found for this pet.</p>
            </div>
        }
        else
        {
            @foreach (var record in records)
            {
                <div class="card medical-record-card">
                    <div class="card-body">
                        <div class="d-flex justify-content-between">
                            <div>
                                <h6 class="card-title">@record.Date.ToString("MMM d, yyyy") — Dr. @record.Veterinarian</h6>
                                <p class="mb-1"><strong>Diagnosis:</strong> @record.Diagnosis</p>
                                <p class="mb-1"><strong>Treatment:</strong> @record.Treatment</p>
                                @if (!string.IsNullOrWhiteSpace(record.Notes))
                                {
                                    <p class="mb-0 text-muted"><strong>Notes:</strong> @record.Notes</p>
                                }
                            </div>
                            <div>
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => EditRecord(record)">Edit</button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        }
    }
</div>

@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private List<MedicalRecord> records = new();
    private bool showForm = false;
    private MedicalRecord? editingRecord;
    private RecordFormModel model = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var context = DbContextFactory.CreateDbContext();
        pet = await context.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == PetId);
        records = await context.MedicalRecords
            .Where(r => r.PetId == PetId)
            .OrderByDescending(r => r.Date)
            .ToListAsync();
    }

    private void ToggleRecordForm()
    {
        showForm = !showForm;
        if (showForm)
        {
            editingRecord = null;
            model = new RecordFormModel { Date = DateTime.Today };
        }
    }

    private void EditRecord(MedicalRecord record)
    {
        editingRecord = record;
        model = new RecordFormModel
        {
            Id = record.Id,
            Date = record.Date,
            Veterinarian = record.Veterinarian,
            Diagnosis = record.Diagnosis,
            Treatment = record.Treatment,
            Notes = record.Notes
        };
        showForm = true;
    }

    private async Task HandleSubmit()
    {
        using var context = DbContextFactory.CreateDbContext();

        if (model.Id > 0)
        {
            var record = await context.MedicalRecords.FindAsync(model.Id);
            if (record != null)
            {
                record.Date = model.Date;
                record.Veterinarian = model.Veterinarian!;
                record.Diagnosis = model.Diagnosis!;
                record.Treatment = model.Treatment!;
                record.Notes = model.Notes ?? string.Empty;
                await context.SaveChangesAsync();
            }
        }
        else
        {
            var record = new MedicalRecord
            {
                PetId = PetId,
                Date = model.Date,
                Veterinarian = model.Veterinarian!,
                Diagnosis = model.Diagnosis!,
                Treatment = model.Treatment!,
                Notes = model.Notes ?? string.Empty
            };
            context.MedicalRecords.Add(record);
            await context.SaveChangesAsync();
        }

        showForm = false;
        editingRecord = null;
        await LoadData();
    }

    private class RecordFormModel
    {
        public int Id { get; set; }

        [Required]
        public DateTime Date { get; set; } = DateTime.Today;

        [Required(ErrorMessage = "Veterinarian is required")]
        public string? Veterinarian { get; set; }

        [Required(ErrorMessage = "Diagnosis is required")]
        public string? Diagnosis { get; set; }

        [Required(ErrorMessage = "Treatment is required")]
        public string? Treatment { get; set; }

        public string? Notes { get; set; }
    }
}

