+        else
+        {
+            model = new PatientFormModel { DateOfBirth = DateTime.Today.AddYears(-1) };
+        }
+    }
+
+    private void OnOwnerSelected() { }
+
+    private async Task HandleSubmit()
+    {
+        errorMessage = null;
+        try
+        {
+            using var context = DbContextFactory.CreateDbContext();
+
+            int ownerId = model.OwnerId;
+            if (ownerId == 0)
+            {
+                if (string.IsNullOrWhiteSpace(model.OwnerFirstName) || string.IsNullOrWhiteSpace(model.OwnerLastName))
+                {
+                    errorMessage = "Owner first and last name are required when creating a new owner.";
+                    return;
+                }
+                var newOwner = new Owner
+                {
+                    FirstName = model.OwnerFirstName!,
+                    LastName = model.OwnerLastName!,
+                    Phone = model.OwnerPhone ?? string.Empty,
+                    Email = model.OwnerEmail ?? string.Empty
+                };
+                context.Owners.Add(newOwner);
+                await context.SaveChangesAsync();
+                ownerId = newOwner.Id;
+            }
+
+            if (model.PetId > 0)
+            {
+                var pet = await context.Pets.FindAsync(model.PetId);
+                if (pet != null)
+                {
+                    pet.Name = model.PetName!;
+                    pet.Species = model.Species!;
+                    pet.Breed = model.Breed ?? string.Empty;
+                    pet.DateOfBirth = model.DateOfBirth;
