+                    pet.OwnerId = ownerId;
+                    await context.SaveChangesAsync();
+                }
+            }
+            else
+            {
+                var pet = new Pet
+                {
+                    Name = model.PetName!,
+                    Species = model.Species!,
+                    Breed = model.Breed ?? string.Empty,
+                    DateOfBirth = model.DateOfBirth,
+                    Weight = model.Weight,
+                    OwnerId = ownerId
+                };
+                context.Pets.Add(pet);
