            </div>
            <div class="col-md-4 mb-3">
                <label class="form-label">End Time *</label>
                <InputSelect class="form-select" @bind-Value="model.EndTimeString">
                    @for (int h = 8; h <= 18; h++)
                    {
                        @for (int m = 0; m < 60; m += 30)
