@code {
    private List<Invoice> invoices = new();
    private decimal totalOutstanding;
    private decimal paidThisMonth;
    private int pendingCount;
    private string statusFilter = "";
    private DateTime? dateFrom;
    private DateTime? dateTo;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var context = DbContextFactory.CreateDbContext();

        // Summary stats
        totalOutstanding = await context.Invoices
            .Where(i => i.PaymentStatus == PaymentStatus.Pending || i.PaymentStatus == PaymentStatus.PartiallyPaid)
            .SumAsync(i => i.TotalAmount);

        var monthStart = new DateTime(DateTime.Today.Year, DateTime.Today.Month, 1);
        paidThisMonth = await context.Payments
            .Where(p => p.PaymentDate >= monthStart)
            .SumAsync(p => p.Amount);

        pendingCount = await context.Invoices
            .CountAsync(i => i.PaymentStatus == PaymentStatus.Pending || i.PaymentStatus == PaymentStatus.PartiallyPaid);

        // Filtered invoices
        var query = context.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<PaymentStatus>(statusFilter, out var status))
        {
            query = query.Where(i => i.PaymentStatus == status);
        }

        if (dateFrom.HasValue)
        {
            query = query.Where(i => i.InvoiceDate >= dateFrom.Value);
        }

        if (dateTo.HasValue)
        {
            query = query.Where(i => i.InvoiceDate <= dateTo.Value);
        }

        invoices = await query.OrderByDescending(i => i.InvoiceDate).ToListAsync();
    }

    private string GetPaymentStatusBadge(PaymentStatus status) => status switch
    {
        PaymentStatus.Pending => "bg-warning text-dark",
        PaymentStatus.Paid => "bg-success",
        PaymentStatus.PartiallyPaid => "bg-info",
        PaymentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

