@code {
    [Parameter] public int InvoiceId { get; set; }

    private Invoice? invoice;
    private List<InvoiceLineItem> lineItems = new();
    private List<Payment> payments = new();
    private decimal totalPaid;
    private bool showPaymentForm = false;
    private PaymentFormModel paymentModel = new();

    // Line item editing
    private bool addingNewLine = false;
    private string newLineDescription = "";
    private int newLineQuantity = 1;
    private decimal newLineUnitPrice = 0;
    private int? editingLineItemId;
    private string editLineDescription = "";
    private int editLineQuantity = 1;
    private decimal editLineUnitPrice = 0;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var context = DbContextFactory.CreateDbContext();
        invoice = await context.Invoices
            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(i => i.Id == InvoiceId);

        lineItems = await context.InvoiceLineItems
            .Where(li => li.InvoiceId == InvoiceId)
            .ToListAsync();

        payments = await context.Payments
            .Where(p => p.InvoiceId == InvoiceId)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();

        totalPaid = payments.Sum(p => p.Amount);
        paymentModel = new PaymentFormModel
        {
            Amount = invoice != null ? invoice.TotalAmount - totalPaid : 0,
            PaymentDate = DateTime.Today
        };
    }

    private void AddLineItem()
    {
        addingNewLine = true;
        newLineDescription = "";
        newLineQuantity = 1;
        newLineUnitPrice = 0;
    }

    private async Task SaveNewLineItem()
    {
        if (string.IsNullOrWhiteSpace(newLineDescription)) return;

        using var context = DbContextFactory.CreateDbContext();
        var item = new InvoiceLineItem
        {
            InvoiceId = InvoiceId,
            Description = newLineDescription,
            Quantity = newLineQuantity,
            UnitPrice = newLineUnitPrice
        };
        context.InvoiceLineItems.Add(item);
        await context.SaveChangesAsync();

        await RecalculateTotal(context);
        addingNewLine = false;
        await LoadData();
    }

    private void EditLineItem(InvoiceLineItem item)
    {
        editingLineItemId = item.Id;
        editLineDescription = item.Description;
        editLineQuantity = item.Quantity;
        editLineUnitPrice = item.UnitPrice;
    }

    private void CancelEditLineItem()
    {
        editingLineItemId = null;
    }

    private async Task SaveLineItem()
    {
        if (editingLineItemId == null) return;

        using var context = DbContextFactory.CreateDbContext();
        var item = await context.InvoiceLineItems.FindAsync(editingLineItemId.Value);
        if (item != null)
        {
            item.Description = editLineDescription;
            item.Quantity = editLineQuantity;
            item.UnitPrice = editLineUnitPrice;
            await context.SaveChangesAsync();
            await RecalculateTotal(context);
        }
        editingLineItemId = null;
        await LoadData();
    }

    private async Task RemoveLineItem(InvoiceLineItem item)
    {
        using var context = DbContextFactory.CreateDbContext();
        var dbItem = await context.InvoiceLineItems.FindAsync(item.Id);
        if (dbItem != null)
        {
            context.InvoiceLineItems.Remove(dbItem);
            await context.SaveChangesAsync();
            await RecalculateTotal(context);
        }
        await LoadData();
    }

    private async Task RecalculateTotal(ApplicationDbContext context)
    {
        var inv = await context.Invoices.FindAsync(InvoiceId);
        if (inv != null)
        {
            var total = await context.InvoiceLineItems
                .Where(li => li.InvoiceId == InvoiceId)
                .SumAsync(li => li.Quantity * li.UnitPrice);
            inv.TotalAmount = total;
            await context.SaveChangesAsync();
        }
    }

    private async Task RecordPayment()
    {
        if (invoice == null) return;

        using var context = DbContextFactory.CreateDbContext();
        var payment = new Payment
        {
            InvoiceId = InvoiceId,
            Amount = paymentModel.Amount,
            PaymentDate = paymentModel.PaymentDate,
            Method = paymentModel.Method,
            Reference = paymentModel.Reference ?? string.Empty
        };
        context.Payments.Add(payment);
        await context.SaveChangesAsync();

        // Update payment status
        var inv = await context.Invoices.FindAsync(InvoiceId);
        if (inv != null)
        {
            var paidTotal = await context.Payments
                .Where(p => p.InvoiceId == InvoiceId)
                .SumAsync(p => p.Amount);
            inv.PaymentStatus = paidTotal >= inv.TotalAmount ? PaymentStatus.Paid
                : paidTotal > 0 ? PaymentStatus.PartiallyPaid
                : PaymentStatus.Pending;
            await context.SaveChangesAsync();
        }

        showPaymentForm = false;
        await LoadData();
    }

    private string GetStatusBadge(PaymentStatus status) => status switch
    {
        PaymentStatus.Pending => "bg-warning text-dark",
        PaymentStatus.Paid => "bg-success",
        PaymentStatus.PartiallyPaid => "bg-info",
        PaymentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private class PaymentFormModel
    {
        [Required]
        [Range(0.01, double.MaxValue, ErrorMessage = "Amount must be greater than 0")]
        public decimal Amount { get; set; }

        [Required]
        public DateTime PaymentDate { get; set; } = DateTime.Today;

        public PaymentMethod Method { get; set; } = PaymentMethod.Cash;

        public string? Reference { get; set; }
    }
}

