@code {
    private List<Appointment> availableAppointments = new();
    private CreateInvoiceModel model = new();
    private string? errorMessage;

    private decimal GrandTotal => model.LineItems.Sum(li => li.Quantity * li.UnitPrice);

    protected override async Task OnInitializedAsync()
    {
        using var context = DbContextFactory.CreateDbContext();
        availableAppointments = await context.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.Status == AppointmentStatus.Completed && a.Invoice == null)
            .OrderByDescending(a => a.StartTime)
            .ToListAsync();

        model.LineItems.Add(new LineItemModel());
    }

    private void AddLineItem()
    {
        model.LineItems.Add(new LineItemModel());
    }

    private void RemoveLineItem(int index)
    {
        if (model.LineItems.Count > 1)
        {
            model.LineItems.RemoveAt(index);
        }
    }

    private async Task HandleSubmit()
    {
        errorMessage = null;

        if (model.AppointmentId == 0)
        {
            errorMessage = "Please select an appointment.";
            return;
        }

        if (!model.LineItems.Any(li => !string.IsNullOrWhiteSpace(li.Description)))
        {
            errorMessage = "Please add at least one line item.";
            return;
        }

        using var context = DbContextFactory.CreateDbContext();

        var invoice = new Invoice
        {
            AppointmentId = model.AppointmentId,
            InvoiceDate = model.InvoiceDate,
            TotalAmount = GrandTotal,
            PaymentStatus = PaymentStatus.Pending
        };
        context.Invoices.Add(invoice);
        await context.SaveChangesAsync();

        foreach (var li in model.LineItems.Where(li => !string.IsNullOrWhiteSpace(li.Description)))
        {
            var lineItem = new InvoiceLineItem
            {
                InvoiceId = invoice.Id,
                Description = li.Description,
                Quantity = li.Quantity,
                UnitPrice = li.UnitPrice
            };
            context.InvoiceLineItems.Add(lineItem);
        }
        await context.SaveChangesAsync();

        Navigation.NavigateTo($"/billing/invoice/{invoice.Id}");
    }

    private class CreateInvoiceModel
    {
        [Range(1, int.MaxValue, ErrorMessage = "Please select an appointment")]
        public int AppointmentId { get; set; }

        public DateTime InvoiceDate { get; set; } = DateTime.Today;

        public List<LineItemModel> LineItems { get; set; } = new();
    }

    private class LineItemModel
    {
        public string Description { get; set; } = string.Empty;
        public int Quantity { get; set; } = 1;
        public decimal UnitPrice { get; set; }
    }
}

@page "/appointments"

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Models

@inject IDbContextFactory<ApplicationDbContext> DbContextFactory

<PageTitle>Appointments</PageTitle>

<div class="container-fluid">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>Appointments</h2>
        <button class="btn btn-primary" @onclick="ShowNewAppointmentForm">➕ New Appointment</button>
    </div>

    <!-- Week Navigation -->
    <div class="d-flex justify-content-between align-items-center mb-3">
        <button class="btn btn-outline-secondary" @onclick="PreviousWeek">← Previous Week</button>
        <div class="text-center">
            <h5 class="mb-0">@weekStart.ToString("MMM d") - @weekStart.AddDays(6).ToString("MMM d, yyyy")</h5>
        </div>
        <div>
            <button class="btn btn-outline-primary me-2" @onclick="GoToToday">Today</button>
            <button class="btn btn-outline-secondary" @onclick="NextWeek">Next Week →</button>
        </div>
    </div>

    @if (showAppointmentForm)
    {
        <VetClinic.Components.Pages.Appointments.AppointmentForm
            Appointment="editingAppointment"
            PrefilledDate="prefilledDate"
            PrefilledStartTime="prefilledStartTime"
            OnSave="HandleAppointmentSaved"
            OnCancel="() => { showAppointmentForm = false; }" />
    }

    @if (selectedAppointment != null && !showAppointmentForm)
    {
        <div class="appointment-detail-overlay" @onclick="CloseDetail">
            <div class="appointment-detail-card" @onclick:stopPropagation>
                <div class="d-flex justify-content-between align-items-start mb-3">
                    <h5>Appointment Details</h5>
                    <button class="btn-close" @onclick="CloseDetail"></button>
                </div>
                <p><strong>Pet:</strong> @selectedAppointment.Pet.Name (@selectedAppointment.Pet.Species)</p>
                <p><strong>Owner:</strong> @selectedAppointment.Pet.Owner.FirstName @selectedAppointment.Pet.Owner.LastName</p>
                <p><strong>Time:</strong> @selectedAppointment.StartTime.ToString("h:mm tt") - @selectedAppointment.EndTime.ToString("h:mm tt")</p>
                <p><strong>Reason:</strong> @selectedAppointment.Reason</p>
                <p><strong>Veterinarian:</strong> @selectedAppointment.Veterinarian</p>
                <p><strong>Status:</strong> <span class="badge @GetStatusBadge(selectedAppointment.Status)">@selectedAppointment.Status</span></p>
                @if (!string.IsNullOrWhiteSpace(selectedAppointment.Notes))
                {
                    <p><strong>Notes:</strong> @selectedAppointment.Notes</p>
                }
                <div class="d-flex gap-2 mt-3">
                    <button class="btn btn-primary btn-sm" @onclick="EditSelectedAppointment">Edit</button>
                    @if (selectedAppointment.Status == AppointmentStatus.Scheduled)
                    {
                        <button class="btn btn-success btn-sm" @onclick="CompleteAppointment">Complete</button>
                        <button class="btn btn-danger btn-sm" @onclick="CancelAppointment">Cancel</button>
                    }
                </div>
            </div>
        </div>
    }

    <!-- Calendar Grid -->
    <div class="calendar-container">
        <div class="calendar-grid">
            <!-- Headers -->
            <div class="calendar-header">Time</div>
            @for (int d = 0; d < 7; d++)
            {
                var day = weekStart.AddDays(d);
                var isToday = day.Date == DateTime.Today;
                <div class="calendar-header @(isToday ? "today" : "")">
                    @day.ToString("ddd M/d")
                </div>
            }

            <!-- Time slots (8 AM - 6 PM, 1-hour slots) -->
            @for (int hour = 8; hour < 18; hour++)
            {
                var h = hour;
                <div class="time-label">@(new TimeOnly(h, 0).ToString("h:mm tt"))</div>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    var isToday = day.Date == DateTime.Today;
                    var slotStart = day.AddHours(h);
                    var slotEnd = day.AddHours(h + 1);
                    var slotAppointments = GetAppointmentsForSlot(slotStart, slotEnd);

                    <div class="calendar-cell @(isToday ? "today" : "")"
                         @onclick="() => OnSlotClicked(slotStart)">
                        @foreach (var apt in slotAppointments)
                        {
                            var statusClass = apt.Status switch
                            {
                                AppointmentStatus.Scheduled => "status-scheduled",
                                AppointmentStatus.Completed => "status-completed",
                                AppointmentStatus.Cancelled => "status-cancelled",
                                _ => ""
                            };
                            <div class="appointment-block @statusClass"
                                 @onclick="() => SelectAppointment(apt)"
                                 @onclick:stopPropagation>
                                @apt.Pet.Name - @apt.Reason
                            </div>
                        }
                    </div>
                }
            }
        </div>
    </div>
</div>

@code {
    private DateTime weekStart;
    private List<Appointment> weekAppointments = new();
    private bool showAppointmentForm = false;
    private Appointment? editingAppointment;
    private Appointment? selectedAppointment;
    private DateTime prefilledDate;
    private TimeSpan prefilledStartTime;

    protected override async Task OnInitializedAsync()
    {
        GoToToday();
        await LoadAppointments();
    }

    private void GoToToday()
    {
        var today = DateTime.Today;
        int diff = (int)today.DayOfWeek - (int)DayOfWeek.Monday;
        if (diff < 0) diff += 7;
        weekStart = today.AddDays(-diff);
    }

    private async Task PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        using var context = DbContextFactory.CreateDbContext();
        var weekEnd = weekStart.AddDays(7);
        weekAppointments = await context.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    private List<Appointment> GetAppointmentsForSlot(DateTime slotStart, DateTime slotEnd)
    {
        return weekAppointments
            .Where(a => a.StartTime < slotEnd && a.EndTime > slotStart)
            .ToList();
    }

    private void OnSlotClicked(DateTime slotStart)
    {
        prefilledDate = slotStart.Date;
        prefilledStartTime = slotStart.TimeOfDay;
        editingAppointment = null;
        showAppointmentForm = true;
        selectedAppointment = null;
    }

    private void SelectAppointment(Appointment apt)
    {
        selectedAppointment = apt;
    }

    private void CloseDetail()
    {
        selectedAppointment = null;
    }

    private void EditSelectedAppointment()
    {
        editingAppointment = selectedAppointment;
        showAppointmentForm = true;
        selectedAppointment = null;
    }

    private void ShowNewAppointmentForm()
    {
        editingAppointment = null;
        prefilledDate = DateTime.Today;
        prefilledStartTime = new TimeSpan(9, 0, 0);
        showAppointmentForm = true;
        selectedAppointment = null;
    }

    private async Task CompleteAppointment()
    {
        if (selectedAppointment == null) return;
        using var context = DbContextFactory.CreateDbContext();
        var apt = await context.Appointments.FindAsync(selectedAppointment.Id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Completed;
            await context.SaveChangesAsync();
        }
        selectedAppointment = null;
        await LoadAppointments();
    }

    private async Task CancelAppointment()
    {
        if (selectedAppointment == null) return;
        using var context = DbContextFactory.CreateDbContext();
        var apt = await context.Appointments.FindAsync(selectedAppointment.Id);
        if (apt != null)
        {
            apt.Status = AppointmentStatus.Cancelled;
            await context.SaveChangesAsync();
        }
        selectedAppointment = null;
        await LoadAppointments();
    }

    private async Task HandleAppointmentSaved()
    {
        showAppointmentForm = false;
        editingAppointment = null;
        await LoadAppointments();
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

