@code {
    [Parameter] public Appointment? Appointment { get; set; }
    [Parameter] public DateTime PrefilledDate { get; set; }
    [Parameter] public TimeSpan PrefilledStartTime { get; set; }
    [Parameter] public EventCallback OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private List<Pet> pets = new();
    private AppointmentFormModel model = new();
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        using var context = DbContextFactory.CreateDbContext();
        pets = await context.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    protected override void OnParametersSet()
    {
        if (Appointment != null && Appointment.Id > 0)
        {
            model = new AppointmentFormModel
            {
                Id = Appointment.Id,
                PetId = Appointment.PetId,
                Date = Appointment.StartTime.Date,
                StartTimeString = Appointment.StartTime.ToString("HH:mm"),
                EndTimeString = Appointment.EndTime.ToString("HH:mm"),
                Reason = Appointment.Reason,
                Veterinarian = Appointment.Veterinarian,
                Notes = Appointment.Notes
            };
        }
        else
        {
            var startTime = PrefilledStartTime == default ? new TimeSpan(9, 0, 0) : PrefilledStartTime;
            model = new AppointmentFormModel
            {
                Date = PrefilledDate == default ? DateTime.Today : PrefilledDate,
                StartTimeString = $"{startTime.Hours:D2}:{startTime.Minutes:D2}",
                EndTimeString = $"{(startTime.Hours + 1):D2}:{startTime.Minutes:D2}"
            };
        }
    }

    private async Task HandleSubmit()
    {
        errorMessage = null;

        if (model.PetId == 0)
        {
            errorMessage = "Please select a pet.";
            return;
        }

        var startTime = model.Date.Add(TimeSpan.Parse(model.StartTimeString));
        var endTime = model.Date.Add(TimeSpan.Parse(model.EndTimeString));

        if (endTime <= startTime)
        {
            errorMessage = "End time must be after start time.";
            return;
        }

        using var context = DbContextFactory.CreateDbContext();

        // Check for vet overlapping appointments
        var overlap = await context.Appointments
            .Where(a => a.Veterinarian == model.Veterinarian
                && a.Status != AppointmentStatus.Cancelled
                && a.StartTime < endTime
                && a.EndTime > startTime
                && a.Id != model.Id)
            .AnyAsync();

        if (overlap)
        {
            errorMessage = "This veterinarian already has an appointment during this time.";
            return;
        }

        if (model.Id > 0)
        {
            var apt = await context.Appointments.FindAsync(model.Id);
            if (apt != null)
            {
                apt.PetId = model.PetId;
                apt.StartTime = startTime;
                apt.EndTime = endTime;
                apt.Reason = model.Reason!;
                apt.Veterinarian = model.Veterinarian!;
                apt.Notes = model.Notes ?? string.Empty;
                await context.SaveChangesAsync();
            }
        }
        else
        {
            var apt = new Appointment
            {
                PetId = model.PetId,
                StartTime = startTime,
                EndTime = endTime,
                Reason = model.Reason!,
                Veterinarian = model.Veterinarian!,
                Notes = model.Notes ?? string.Empty,
                Status = AppointmentStatus.Scheduled
            };
            context.Appointments.Add(apt);
            await context.SaveChangesAsync();
        }

        await OnSave.InvokeAsync();
    }

    private async Task HandleCancel() => await OnCancel.InvokeAsync();

    private class AppointmentFormModel
    {
        public int Id { get; set; }

        [Range(1, int.MaxValue, ErrorMessage = "Please select a pet")]
        public int PetId { get; set; }

        [Required]
        public DateTime Date { get; set; } = DateTime.Today;

        [Required]
        public string StartTimeString { get; set; } = "09:00";

        [Required]
        public string EndTimeString { get; set; } = "10:00";

        [Required(ErrorMessage = "Reason is required")]
        public string? Reason { get; set; }

        [Required(ErrorMessage = "Veterinarian is required")]
        public string? Veterinarian { get; set; }

        public string? Notes { get; set; }
    }
}

