                <option value="Cancelled">Cancelled</option>
            </select>
        </div>
        <div class="col-md-3">
            <label class="form-label">From Date</label>
            <input type="date" class="form-control" @bind="dateFrom" @bind:after="LoadData" />
        </div>
        <div class="col-md-3">
            <label class="form-label">To Date</label>
            <input type="date" class="form-control" @bind="dateTo" @bind:after="LoadData" />
        </div>
