+                        <button class="btn btn-success btn-sm" @onclick="CompleteAppointment">Complete</button>
+                        <button class="btn btn-danger btn-sm" @onclick="CancelAppointment">Cancel</button>
+                    }
+                </div>
+            </div>
+        </div>
+    }
+
+    <!-- Calendar Grid -->
+    <div class="calendar-container">
+        <div class="calendar-grid">
+            <!-- Headers -->
+            <div class="calendar-header">Time</div>
+            @for (int d = 0; d < 7; d++)
+            {
+                var day = weekStart.AddDays(d);
+                var isToday = day.Date == DateTime.Today;
+                <div class="calendar-header @(isToday ? "today" : "")">
+                    @day.ToString("ddd M/d")
+                </div>
+            }
+
+            <!-- Time slots (8 AM - 6 PM, 1-hour slots) -->
+            @for (int hour = 8; hour < 18; hour++)
+            {
+                var h = hour;
+                <div class="time-label">@(new TimeOnly(h, 0).ToString("h:mm tt"))</div>
+                @for (int d = 0; d < 7; d++)
+                {
+                    var day = weekStart.AddDays(d);
+                    var isToday = day.Date == DateTime.Today;
+                    var slotStart = day.AddHours(h);
+                    var slotEnd = day.AddHours(h + 1);
+                    var slotAppointments = GetAppointmentsForSlot(slotStart, slotEnd);
+
+                    <div class="calendar-cell @(isToday ? "today" : "")"
+                         @onclick="() => OnSlotClicked(slotStart)">
+                        @foreach (var apt in slotAppointments)
+                        {
+                            var statusClass = apt.Status switch
+                            {
+                                AppointmentStatus.Scheduled => "status-scheduled",
+                                AppointmentStatus.Completed => "status-completed",
+                                AppointmentStatus.Cancelled => "status-cancelled",
+                                _ => ""
+                            };
+                            <div class="appointment-block @statusClass"
+                                 @onclick="() => SelectAppointment(apt)"
+                                 @onclick:stopPropagation>
+                                @apt.Pet.Name - @apt.Reason
+                            </div>
+                        }
+                    </div>
+                }
+            }
+        </div>
+    </div>
+</div>
+
+@code {
+    private DateTime weekStart;
+    private List<Appointment> weekAppointments = new();
+    private bool showAppointmentForm = false;
+    private Appointment? editingAppointment;
+    private Appointment? selectedAppointment;
+    private DateTime prefilledDate;
+    private TimeSpan prefilledStartTime;
+
+    protected override async Task OnInitializedAsync()
+    {
+        GoToToday();
+        await LoadAppointments();
+    }
+
+    private void GoToToday()
+    {
+        var today = DateTime.Today;
+        int diff = (int)today.DayOfWeek - (int)DayOfWeek.Monday;
+        if (diff < 0) diff += 7;
+        weekStart = today.AddDays(-diff);
+    }
+
+    private async Task PreviousWeek()
+    {
+        weekStart = weekStart.AddDays(-7);
+        await LoadAppointments();
+    }
+
+    private async Task NextWeek()
+    {
+        weekStart = weekStart.AddDays(7);
+        await LoadAppointments();
+    }
+
+    private async Task LoadAppointments()
+    {
+        using var context = DbContextFactory.CreateDbContext();
+        var weekEnd = weekStart.AddDays(7);
+        weekAppointments = await context.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd)
+            .OrderBy(a => a.StartTime)
+            .ToListAsync();
+    }
+
+    private List<Appointment> GetAppointmentsForSlot(DateTime slotStart, DateTime slotEnd)
+    {
+        return weekAppointments
+            .Where(a => a.StartTime < slotEnd && a.EndTime > slotStart)
+            .ToList();
+    }
+
+    private void OnSlotClicked(DateTime slotStart)
+    {
+        prefilledDate = slotStart.Date;
+        prefilledStartTime = slotStart.TimeOfDay;
+        editingAppointment = null;
+        showAppointmentForm = true;
+        selectedAppointment = null;
+    }
+
+    private void SelectAppointment(Appointment apt)
+    {
+        selectedAppointment = apt;
+    }
+
+    private void CloseDetail()
+    {
+        selectedAppointment = null;
+    }
+
+    private void EditSelectedAppointment()
+    {
+        editingAppointment = selectedAppointment;
+        showAppointmentForm = true;
+        selectedAppointment = null;
+    }
+
+    private void ShowNewAppointmentForm()
+    {
+        editingAppointment = null;
+        prefilledDate = DateTime.Today;
+        prefilledStartTime = new TimeSpan(9, 0, 0);
+        showAppointmentForm = true;
+        selectedAppointment = null;
+    }
+
+    private async Task CompleteAppointment()
+    {
+        if (selectedAppointment == null) return;
+        using var context = DbContextFactory.CreateDbContext();
+        var apt = await context.Appointments.FindAsync(selectedAppointment.Id);
+        if (apt != null)
+        {
+            apt.Status = AppointmentStatus.Completed;
+            await context.SaveChangesAsync();
+        }
+        selectedAppointment = null;
+        await LoadAppointments();
+    }
+
+    private async Task CancelAppointment()
+    {
+        if (selectedAppointment == null) return;
+        using var context = DbContextFactory.CreateDbContext();
+        var apt = await context.Appointments.FindAsync(selectedAppointment.Id);
+        if (apt != null)
+        {
+            apt.Status = AppointmentStatus.Cancelled;
+            await context.SaveChangesAsync();
+        }
+        selectedAppointment = null;
+        await LoadAppointments();
+    }
+
+    private async Task HandleAppointmentSaved()
+    {
+        showAppointmentForm = false;
+        editingAppointment = null;
+        await LoadAppointments();
+    }
+
+    private string GetStatusBadge(AppointmentStatus status) => status switch
+    {
+        AppointmentStatus.Scheduled => "bg-primary",
+        AppointmentStatus.Completed => "bg-success",
+        AppointmentStatus.Cancelled => "bg-danger",
+        _ => "bg-secondary"
+    };
+}
+

