@@ -1,0 +1,392 @@
+@page "/billing/invoice/{InvoiceId:int}"
+
+@using Microsoft.EntityFrameworkCore
+@using VetClinic.Data
+@using VetClinic.Models
+@using System.ComponentModel.DataAnnotations
+
+@inject IDbContextFactory<ApplicationDbContext> DbContextFactory
+@inject NavigationManager Navigation
+
+<PageTitle>Invoice Detail</PageTitle>
+
+<div class="container-fluid">
+    <button class="btn btn-outline-secondary btn-sm mb-3" @onclick='() => Navigation.NavigateTo("/billing")'>← Back to Billing</button>
+
+    @if (invoice == null)
+    {
+        <p>Loading...</p>
+    }
+    else
+    {
+        <div class="d-flex justify-content-between align-items-center mb-3">
+            <h2>Invoice INV-@invoice.Id.ToString("D5")</h2>
+            <span class="badge @GetStatusBadge(invoice.PaymentStatus) fs-6">@invoice.PaymentStatus</span>
+        </div>
+
+        <div class="row mb-4">
+            <div class="col-md-6">
+                <div class="card">
+                    <div class="card-body">
+                        <h6>Invoice Information</h6>
+                        <p class="mb-1"><strong>Date:</strong> @invoice.InvoiceDate.ToString("MMM d, yyyy")</p>
+                        <p class="mb-1"><strong>Pet:</strong> @invoice.Appointment.Pet.Name (@invoice.Appointment.Pet.Species)</p>
+                        <p class="mb-1"><strong>Owner:</strong> @invoice.Appointment.Pet.Owner.FirstName @invoice.Appointment.Pet.Owner.LastName</p>
+                        <p class="mb-1"><strong>Appointment:</strong> @invoice.Appointment.StartTime.ToString("MMM d, yyyy h:mm tt")</p>
+                        <p class="mb-0"><strong>Reason:</strong> @invoice.Appointment.Reason</p>
+                    </div>
+                </div>
+            </div>
+            <div class="col-md-6">
+                <div class="card">
+                    <div class="card-body">
+                        <h6>Payment Summary</h6>
+                        <p class="mb-1"><strong>Total:</strong> $@invoice.TotalAmount.ToString("N2")</p>
+                        <p class="mb-1"><strong>Paid:</strong> $@totalPaid.ToString("N2")</p>
+                        <p class="mb-0"><strong>Balance:</strong> $@((invoice.TotalAmount - totalPaid).ToString("N2"))</p>
+                    </div>
+                </div>
+            </div>
+        </div>
+
+        <!-- Line Items -->
+        <div class="card mb-4">
+            <div class="card-header d-flex justify-content-between align-items-center">
+                <h5 class="mb-0">Line Items</h5>
+                <button class="btn btn-sm btn-outline-primary" @onclick="AddLineItem">+ Add Item</button>
+            </div>
+            <div class="card-body">
+                <table class="table">
+                    <thead>
+                        <tr>
+                            <th>Description</th>
+                            <th style="width:100px">Qty</th>
+                            <th style="width:120px">Unit Price</th>
+                            <th style="width:120px">Total</th>
+                            <th style="width:80px"></th>
+                        </tr>
+                    </thead>
+                    <tbody>
+                        @foreach (var item in lineItems)
+                        {
+                            <tr>
+                                @if (editingLineItemId == item.Id)
+                                {
+                                    <td><input class="form-control form-control-sm" @bind="editLineDescription" /></td>
+                                    <td><input type="number" class="form-control form-control-sm" @bind="editLineQuantity" min="1" /></td>
+                                    <td><input type="number" class="form-control form-control-sm" @bind="editLineUnitPrice" step="0.01" /></td>
+                                    <td>$@((editLineQuantity * editLineUnitPrice).ToString("N2"))</td>
+                                    <td>
+                                        <button class="btn btn-sm btn-success" @onclick="SaveLineItem">✓</button>
+                                        <button class="btn btn-sm btn-secondary" @onclick="CancelEditLineItem">✕</button>
+                                    </td>
+                                }
+                                else
+                                {
+                                    <td>@item.Description</td>
+                                    <td>@item.Quantity</td>
+                                    <td>$@item.UnitPrice.ToString("N2")</td>
+                                    <td>$@item.Total.ToString("N2")</td>
+                                    <td>
+                                        <button class="btn btn-sm btn-outline-primary" @onclick="() => EditLineItem(item)">✎</button>
+                                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveLineItem(item)">✕</button>
+                                    </td>
+                                }
+                            </tr>
+                        }
+                        @if (addingNewLine)
+                        {
+                            <tr>
+                                <td><input class="form-control form-control-sm" @bind="newLineDescription" placeholder="Description" /></td>
+                                <td><input type="number" class="form-control form-control-sm" @bind="newLineQuantity" min="1" /></td>
+                                <td><input type="number" class="form-control form-control-sm" @bind="newLineUnitPrice" step="0.01" /></td>
+                                <td>$@((newLineQuantity * newLineUnitPrice).ToString("N2"))</td>
+                                <td>
+                                    <button class="btn btn-sm btn-success" @onclick="SaveNewLineItem">✓</button>
+                                    <button class="btn btn-sm btn-secondary" @onclick="() => addingNewLine = false">✕</button>
+                                </td>
+                            </tr>
+                        }
+                    </tbody>
+                    <tfoot>
+                        <tr class="table-light">
+                            <td colspan="3" class="text-end"><strong>Grand Total:</strong></td>
+                            <td><strong>$@lineItems.Sum(li => li.Total).ToString("N2")</strong></td>
+                            <td></td>
+                        </tr>
+                    </tfoot>
+                </table>
+            </div>
+        </div>
+
+        <!-- Payments -->
+        <div class="card mb-4">
+            <div class="card-header d-flex justify-content-between align-items-center">
+                <h5 class="mb-0">Payments</h5>
+                @if (invoice.PaymentStatus != PaymentStatus.Paid)
+                {
+                    <button class="btn btn-sm btn-outline-success" @onclick="() => showPaymentForm = !showPaymentForm">
+                        @(showPaymentForm ? "Cancel" : "💰 Record Payment")
+                    </button>
+                }
+            </div>
+            <div class="card-body">
+                @if (showPaymentForm)
+                {
+                    <div class="form-section">
+                        <EditForm Model="paymentModel" OnValidSubmit="RecordPayment" FormName="paymentForm">
+                            <DataAnnotationsValidator />
+                            <ValidationSummary class="text-danger" />
+                            <div class="row">
+                                <div class="col-md-3 mb-3">
+                                    <label class="form-label">Amount *</label>
+                                    <InputNumber class="form-control" @bind-Value="paymentModel.Amount" />
+                                    <ValidationMessage For="() => paymentModel.Amount" />
+                                </div>
+                                <div class="col-md-3 mb-3">
+                                    <label class="form-label">Method *</label>
+                                    <InputSelect class="form-select" @bind-Value="paymentModel.Method">
+                                        @foreach (var method in Enum.GetValues<PaymentMethod>())
+                                        {
+                                            <option value="@method">@method</option>
+                                        }
+                                    </InputSelect>
+                                </div>
+                                <div class="col-md-3 mb-3">
+                                    <label class="form-label">Date *</label>
+                                    <InputDate class="form-control" @bind-Value="paymentModel.PaymentDate" />
+                                </div>
+                                <div class="col-md-3 mb-3">
+                                    <label class="form-label">Reference</label>
+                                    <InputText class="form-control" @bind-Value="paymentModel.Reference" />
+                                </div>
+                            </div>
+                            <button type="submit" class="btn btn-success">Record Payment</button>
+                        </EditForm>
+                    </div>
+                }
+
+                @if (payments.Count == 0)
+                {
+                    <p class="text-muted">No payments recorded.</p>
+                }
+                else
+                {
+                    <table class="table">
+                        <thead>
+                            <tr>
+                                <th>Date</th>
+                                <th>Amount</th>
+                                <th>Method</th>
+                                <th>Reference</th>
+                            </tr>
+                        </thead>
+                        <tbody>
+                            @foreach (var payment in payments)
+                            {
+                                <tr>
+                                    <td>@payment.PaymentDate.ToString("MMM d, yyyy")</td>
+                                    <td>$@payment.Amount.ToString("N2")</td>
+                                    <td>@payment.Method</td>
+                                    <td>@payment.Reference</td>
+                                </tr>
+                            }
+                        </tbody>
+                    </table>
+                }
+            </div>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public int InvoiceId { get; set; }
+
+    private Invoice? invoice;
+    private List<InvoiceLineItem> lineItems = new();
+    private List<Payment> payments = new();
+    private decimal totalPaid;
+    private bool showPaymentForm = false;
+    private PaymentFormModel paymentModel = new();
+
+    // Line item editing
+    private bool addingNewLine = false;
+    private string newLineDescription = "";
+    private int newLineQuantity = 1;
+    private decimal newLineUnitPrice = 0;
+    private int? editingLineItemId;
+    private string editLineDescription = "";
+    private int editLineQuantity = 1;
+    private decimal editLineUnitPrice = 0;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadData();
+    }
+
+    private async Task LoadData()
+    {
+        using var context = DbContextFactory.CreateDbContext();
+        invoice = await context.Invoices
+            .Include(i => i.Appointment).ThenInclude(a => a.Pet).ThenInclude(p => p.Owner)
+            .FirstOrDefaultAsync(i => i.Id == InvoiceId);
+
+        lineItems = await context.InvoiceLineItems
+            .Where(li => li.InvoiceId == InvoiceId)
+            .ToListAsync();
+
+        payments = await context.Payments
+            .Where(p => p.InvoiceId == InvoiceId)
+            .OrderByDescending(p => p.PaymentDate)
+            .ToListAsync();
+
+        totalPaid = payments.Sum(p => p.Amount);
+        paymentModel = new PaymentFormModel
+        {
+            Amount = invoice != null ? invoice.TotalAmount - totalPaid : 0,
+            PaymentDate = DateTime.Today
+        };
+    }
+
+    private void AddLineItem()
+    {
+        addingNewLine = true;
+        newLineDescription = "";
+        newLineQuantity = 1;
+        newLineUnitPrice = 0;
+    }
+
+    private async Task SaveNewLineItem()
+    {
+        if (string.IsNullOrWhiteSpace(newLineDescription)) return;
+
+        using var context = DbContextFactory.CreateDbContext();
+        var item = new InvoiceLineItem
+        {
+            InvoiceId = InvoiceId,
+            Description = newLineDescription,
+            Quantity = newLineQuantity,
+            UnitPrice = newLineUnitPrice
+        };
+        context.InvoiceLineItems.Add(item);
+        await context.SaveChangesAsync();
+
+        await RecalculateTotal(context);
+        addingNewLine = false;
+        await LoadData();
+    }
+
+    private void EditLineItem(InvoiceLineItem item)
+    {
+        editingLineItemId = item.Id;
+        editLineDescription = item.Description;
+        editLineQuantity = item.Quantity;
+        editLineUnitPrice = item.UnitPrice;
+    }
+
+    private void CancelEditLineItem()
+    {
+        editingLineItemId = null;
+    }
+
+    private async Task SaveLineItem()
+    {
+        if (editingLineItemId == null) return;
+
+        using var context = DbContextFactory.CreateDbContext();
+        var item = await context.InvoiceLineItems.FindAsync(editingLineItemId.Value);
+        if (item != null)
+        {
+            item.Description = editLineDescription;
+            item.Quantity = editLineQuantity;
+            item.UnitPrice = editLineUnitPrice;
+            await context.SaveChangesAsync();
+            await RecalculateTotal(context);
+        }
+        editingLineItemId = null;
+        await LoadData();
+    }
+
+    private async Task RemoveLineItem(InvoiceLineItem item)
+    {
+        using var context = DbContextFactory.CreateDbContext();
+        var dbItem = await context.InvoiceLineItems.FindAsync(item.Id);
+        if (dbItem != null)
+        {
+            context.InvoiceLineItems.Remove(dbItem);
+            await context.SaveChangesAsync();
+            await RecalculateTotal(context);
+        }
+        await LoadData();
+    }
+
+    private async Task RecalculateTotal(ApplicationDbContext context)
+    {
+        var inv = await context.Invoices.FindAsync(InvoiceId);
+        if (inv != null)
+        {
+            var total = await context.InvoiceLineItems
+                .Where(li => li.InvoiceId == InvoiceId)
+                .SumAsync(li => li.Quantity * li.UnitPrice);
+            inv.TotalAmount = total;
+            await context.SaveChangesAsync();
+        }
+    }
+
+    private async Task RecordPayment()
+    {
+        if (invoice == null) return;
+
+        using var context = DbContextFactory.CreateDbContext();
+        var payment = new Payment
+        {
+            InvoiceId = InvoiceId,
+            Amount = paymentModel.Amount,
+            PaymentDate = paymentModel.PaymentDate,
+            Method = paymentModel.Method,
+            Reference = paymentModel.Reference ?? string.Empty
+        };
+        context.Payments.Add(payment);
+        await context.SaveChangesAsync();
+
+        // Update payment status
+        var inv = await context.Invoices.FindAsync(InvoiceId);
+        if (inv != null)
+        {
+            var paidTotal = await context.Payments
+                .Where(p => p.InvoiceId == InvoiceId)
+                .SumAsync(p => p.Amount);
+            inv.PaymentStatus = paidTotal >= inv.TotalAmount ? PaymentStatus.Paid
+                : paidTotal > 0 ? PaymentStatus.PartiallyPaid
+                : PaymentStatus.Pending;
+            await context.SaveChangesAsync();
+        }
+
+        showPaymentForm = false;
+        await LoadData();
+    }
+
+    private string GetStatusBadge(PaymentStatus status) => status switch
+    {
+        PaymentStatus.Pending => "bg-warning text-dark",
+        PaymentStatus.Paid => "bg-success",
+        PaymentStatus.PartiallyPaid => "bg-info",
+        PaymentStatus.Cancelled => "bg-danger",
+        _ => "bg-secondary"
+    };
+
+    private class PaymentFormModel
+    {
+        [Required]
+        [Range(0.01, double.MaxValue, ErrorMessage = "Amount must be greater than 0")]
+        public decimal Amount { get; set; }
+
+        [Required]
+        public DateTime PaymentDate { get; set; } = DateTime.Today;
+
+        public PaymentMethod Method { get; set; } = PaymentMethod.Cash;
+
+        public string? Reference { get; set; }
+    }
+}
+

